      "subtask": "Perform the circular right-shift for the normal case",
      "atomics": [
        "Compute effective_shift = shift % n to collapse full-rotation no-ops (handles shift == n as identity)",
        "Slice s as s[-effective_shift:] + s[:-effective_shift] to move the last effective_shift digits to the front",
        "Return the concatenated string"
      ]
    }
  ],
  "global_atomics": [
    "Verify against doctests: circular_shift(12, 1) == '21' and circular_shift(12, 2) == '12'",
