  "gold_actions": {
    "global": "Write the function body: s=str(x), n=len(s), return s[::-1] if shift>n else s[-shift%n or n:]+s[:-shift%n or n] (equivalently, use the slice form after clamping).",
    "subtasks": [
      {
        "subtask": "Convert integer x to digit string and record its length",
        "atomics": [
          "Execute s = str(x)",
          "Execute n = len(s)"
        ]
