          "Evaluate the condition shift > n",
          "Execute return s[::-1] in the true branch"
        ]
      },
      {
        "subtask": "Compute and return the right-rotated string for shift <= n",
        "atomics": [
          "Compute effective = shift % n (yields 0 when shift==n, preserving identity)",
          "Form rotated = s[-effective:] + s[:-effective] if effective != 0 else s",
          "Execute return rotated"
        ]
      }
    ],
    "global_atomics": [
      "Run doctest: assert circular_shift(12, 1) == '21' and circular_shift(12, 2) == '12'",
      "Run edge-case check: assert circular_shift(12, 0) == '12'"
